function simpleHash(str) {
  let h1 = 5381, h2 = 52711;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = ((h1 << 5) + h1 + ch) >>> 0;
    h2 = ((h2 << 5) + h2 + ch) >>> 0;
  }
  const a = h1.toString(16).padStart(8, '0');
  const b = h2.toString(16).padStart(8, '0');
  return (a + b + a + b + a + b + a + b).substring(0, 64);
}

// Skip items older than this; also skip items with no parseable date.
const MAX_AGE_MS = 7 * 24 * 60 * 60 * 1000;
const nowMs = Date.now();
function tooOld(pubMs) {
  if (!Number.isFinite(pubMs)) return true;
  return (nowMs - pubMs) > MAX_AGE_MS;
}

const results = [];
const allInputs = $input.all();
const sourceInputs = $('Split Sources').all();

for (let idx = 0; idx < allInputs.length; idx++) {
  const item = allInputs[idx];
  const src = sourceInputs[idx]?.json;
  if (!src) continue;

  const responseData = item.json;

  try {
    if (src.source_type === 'rss') {
      let text = '';
      if (typeof responseData === 'string') {
        text = responseData;
      } else if (typeof responseData.data === 'string') {
        text = responseData.data;
      } else {
        text = JSON.stringify(responseData);
      }

      if (!text.includes('<') || text.length < 100) continue;

      const itemRegex = /<item[\s>][\s\S]*?<\/item>|<entry[\s>][\s\S]*?<\/entry>/gi;
      let match;
      let count = 0;
      while ((match = itemRegex.exec(text)) !== null && count < 20) {
        const block = match[0];
        const getTag = (tag) => {
          const m = block.match(new RegExp(`<${tag}[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/${tag}>`, 's'));
          return m ? m[1].trim() : null;
        };
        const getAttr = (tag, attr) => {
          const m = block.match(new RegExp(`<${tag}[^>]*${attr}="([^"]*)"`, 's'));
          return m ? m[1] : null;
        };

        const title = getTag('title');
        const link = getTag('link') || getAttr('link', 'href');
        if (!title || !link) continue;

        const desc = getTag('description') || getTag('summary') || getTag('content');
        const pubDate = getTag('pubDate') || getTag('published') || getTag('updated');
        const author = getTag('creator') || getTag('author') || getTag('dc:creator');
        const snippet = desc ? desc.replace(/<[^>]*>/g, '').replace(/&[^;]+;/g, ' ').substring(0, 500) : '';

        const pubMs = pubDate ? new Date(pubDate).getTime() : NaN;
        if (tooOld(pubMs)) continue;
        const parsedDate = new Date(pubMs).toISOString().slice(0, 19).replace('T', ' ');

        results.push({
          title: title.substring(0, 500),
          url: link,
          url_hash: simpleHash(link),
          author: author || null,
          published_at: parsedDate,
          content_snippet: snippet,
          source_id: src.id,
          topic: src.topic
        });
        count++;
      }
    } else if (src.source_type === 'reddit') {
      let jsonData = responseData;
      if (typeof jsonData === 'string') {
        try { jsonData = JSON.parse(jsonData); } catch(e) { continue; }
      }

      const children = jsonData?.data?.children || [];
      if (children.length === 0) continue;

      for (const c of children) {
        const d = c.data;
        if (!d || d.stickied) continue;

        const permalink = d.permalink || '';
        const postUrl = d.is_self ? 'https://www.reddit.com' + permalink : (d.url || 'https://www.reddit.com' + permalink);
        const urlHash = simpleHash(postUrl);
        const pubMs = d.created_utc ? d.created_utc * 1000 : NaN;
        if (tooOld(pubMs)) continue;
        const pubDate = new Date(pubMs).toISOString().slice(0, 19).replace('T', ' ');

        results.push({
          title: (d.title || '').substring(0, 500),
          url: postUrl,
          url_hash: urlHash,
          author: d.author || null,
          published_at: pubDate,
          content_snippet: (d.selftext || '').substring(0, 500),
          source_id: src.id,
          topic: src.topic
        });
      }
    }
  } catch (e) {
    // Skip failed sources
  }
}

if (results.length === 0) {
  return [{ json: { items: [], count: 0 } }];
}

return [{ json: { items: results, count: results.length } }];

const items = $json.items || [];
if (items.length === 0) return [{ json: { items: [], hashQuery: 'SELECT "none" as url_hash WHERE 0', noItems: true } }];

const hashes = items.map(i => "'" + i.url_hash + "'").join(',');
return [{ json: { items, hashQuery: 'SELECT url_hash FROM news_articles WHERE url_hash IN (' + hashes + ')', noItems: false } }];

const allItems = $('Prep Dedup').first().json.items || [];
if (allItems.length === 0) return [{ json: { count: 0, combinedSQL: 'SELECT 1', message: 'No items' } }];

const existingRows = $input.all()
  .map(i => i.json?.url_hash)
  .filter(Boolean);
const existingSet = new Set(existingRows);
const newItems = allItems.filter(item => !existingSet.has(item.url_hash));

if (newItems.length === 0) {
  return [{ json: { count: 0, combinedSQL: 'SELECT 1', message: 'All articles already seen' } }];
}

const inserts = newItems.map(item => {
  const esc = (v) => {
    if (!v) return 'NULL';
    return "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
  };
  return `INSERT IGNORE INTO news_articles (source_id, title, url, author, published_at, content_snippet, ai_summary, ai_tags, relevance_score, topic, url_hash) VALUES (${item.source_id}, ${esc(item.title)}, ${esc(item.url)}, ${esc(item.author)}, ${item.published_at ? esc(item.published_at) : 'NULL'}, ${esc(item.content_snippet)}, NULL, '[]', 5, ${esc(item.topic)}, ${esc(item.url_hash)})`;
});

// Emit one item per batch so the MySQL node runs each batch.
const batchSize = 50;
const batches = [];
for (let i = 0; i < inserts.length; i += batchSize) {
  batches.push(inserts.slice(i, i + batchSize).join(';\n'));
}

return batches.map((sql, idx) => ({
  json: {
    count: newItems.length,
    batchIndex: idx,
    batchTotal: batches.length,
    combinedSQL: sql
  }
}));
